export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:15。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "禮堂側廊。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言靠在牆上。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是靠。是沒有力氣站直了。背脊貼著水泥牆面，肩膀往下塌，頭低著，下巴幾乎碰到鎖骨。相機包掛在身側，帶子鬆了，包底蹭著牆壁。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說不出話。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是不想說。是喉嚨裡有什麼東西堵住了——不是眼淚，不是痰，是一種更硬的、像石頭一樣的東西，卡在聲帶和舌根之間。他張了一下嘴。什麼都沒出來。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）二號冰敷櫃。紅色盤點標籤。校安失物保管袋。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）全部命中。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）核心同盟之外，只有他聽過完整版本。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只有他。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊另一端，閉幕背景音樂從禮堂裡滲出來。鋼琴和弦樂攪在一起，聽起來像慶祝。牆壁另一邊有人在笑。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的手指摳著牆面。指甲刮過水泥，發出很細的聲響。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）七年。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他照顧了我七年。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）外套太薄的時候他會說。沒吃飯的時候他會問。我被同學議論的時候他——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他在看我。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）每一次。每一次他問我「有沒有想起小時候的事」，不是在關心我。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是在確認。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）確認我還沒想起密碼。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）確認我還有用。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的後腦勺磕在牆上。不重。但那一下震動讓他清醒了半秒。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不對。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是「還有用」。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是——他一直在等我記起來。等密碼完整。等他可以從我身上拿走最後那把鑰匙。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）然後——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——再處理我。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他閉上眼睛。雨聲從窗戶外面灌進來。禮堂裡的音樂切了一首。更歡快的。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在慶祝的牆壁外面。像每一次。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很穩。不急。膠底鞋踩過走廊地面的節奏太均勻了——和所有校慶裡隨意走動的人不一樣。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從走廊轉角走過來。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "攝影背心。藍色工作證。相機包斜挎在身側。碎髮被濕氣黏在耳側。她看見他靠在牆上，腳步沒有停。走到他面前，站定。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有蹲下來。沒有伸手。沒有問「你怎麼了」。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著他。三秒。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "還能走嗎。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。是確認。語氣平得像在問今天有沒有帶傘。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有立刻回答。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是因為不能。是因為他還沒決定。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯能走嗎。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）腿是軟的。腦子是空的。心裡有一個洞，像被人用手伸進去掏空了。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不走又能怎樣。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）站在這裡，邵叔不會因為我難過就停下來。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低下頭。看見相機包的背帶鬆了，帶子從肩上滑下來半截，包底蹭著牆壁。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他伸手。把背帶拉回來。扣緊。金屬扣件咔嗒一聲。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他把手掌撐在牆面上。指尖發白。把自己從牆邊推起來。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站直了。不穩。但站著。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯能。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個字。聲音很輕。像從很深的水底浮上來的一個氣泡。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "知道是誰不是結束。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "證據還沒出去。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說這兩句話的時候沒有看他。她在看走廊兩端。確認沒有人。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她說得對。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）知道是邵叔。然後呢？", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）密碼沒解。檔案沒出去。韓越被擋在外面。23:00 直播切換越來越近。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）知道兇手是誰——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——不等於救得了她。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他吸了一口氣。走廊裡的空氣是冷的，帶著雨水的腥味和禮堂裡飄出來的暖氣。兩種溫度在他胸腔裡撞在一起。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "這一輪先躲過 23:00。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳活著就好。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說這句話的時候聲音很低。低到像在對自己說。像在說服自己。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）先讓她活。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）密碼下一輪再想。證據下一輪再送。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她只要活過 23:00——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我就能記住這一輪的所有東西。下一輪再來。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠轉過頭。看著他。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那雙深水的眼睛。看得到表面。猜不到深度。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "只要證據沒出去，他明天一樣能用「保護學生」的名義把我帶走。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音沒有升高。沒有顫抖。每一個字都像被精確控制過——不大到被第三個人聽見，也不小到讓他聽不清。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你可以記得下一輪。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我不行。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "對我來說，今晚就是全部。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊裡安靜了。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "禮堂裡的音樂還在響。雨還在打窗戶。但走廊裡——在兩個人之間——安靜得像被抽掉了空氣。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她說——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「你可以記得下一輪，我不行。」", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不知道循環。她不知道重置。她不知道我已經死了六次。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但她知道——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——如果今晚沒有把證據送出去，她的命就不是她的。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是今晚。是明天。後天。每一天。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只要邵叔還在。只要權限還在。只要那些紀錄還沒被翻過來——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她隨時可以被「保護學生」帶走。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）相機隨時可以被「安全保管」收走。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她母親的證據隨時可以消失。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——然後沒有人會知道。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著許星棠。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在那裡。相機包的帶子勒進背心肩線裡。藍色工作證在冷光下反著光。她的表情沒有變——不是冷漠，是節制。是一個知道自己沒有重來機會的人，把所有力氣都收進了最必要的字裡。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我一直以為——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）先讓她活。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）先躲過 23:00。先不要死。其他的事，下一輪再說。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但她說得對。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）躲過 23:00 不是破局。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她活著，但證據沒出去——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——她還是會死。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只是不是今晚。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）明天。後天。下一次邵叔用「保護」的名義走過來的時候。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）所以——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不能只救她。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）要讓真相出去。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這兩件事——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——是同一件事。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站直了。比剛才直。肩膀還在抖，但腳踩穩了。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯走。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "直播備份線。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "23:00 前。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看了他一眼。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那一眼很短。不到一秒。但顧言覺得她在確認的東西，比「還能走嗎」更多。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "韓越在舞台側門等我們。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "走。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉身。腳步聲重新開始——和來時一樣均勻、一樣穩。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言跟上去。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "相機包的背帶扣緊了，勒在肩上。金屬扣件隨著步伐發出很輕的聲響。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手還在抖。但不是因為冷。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一輩子你教我的最後一件事——", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——不是怎麼保護自己。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是怎麼看出誰在用「保護」殺人。", background: Background.Chapter_7_Ch7_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊盡頭的燈閃了一下。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨更大了。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:17。", background: Background.Chapter_7_Ch7_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們往直播備份線的方向走。身後，禮堂裡的掌聲又響了一輪。像在替他們倒數。", background: Background.Chapter_7_Ch7_Act13_S0 },
];
